// Summary: Verifies RadioButtonGroup accessible names, aria-describedby combinations, choice labels and hints, selection callbacks, disabled enforcement, info popover logic, and id generation.

import '@testing-library/jest-dom';
import * as React from 'react';
import { render, screen, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import type { RenderResult } from '@testing-library/react';
import { RadioButtonGroup, type RadioButtonGroupProps } from './RadioButtonGroup';

const baseChoices: RadioButtonGroupProps['choices'] = [
  { value: 'email', label: 'Email updates' },
  { value: 'sms', label: 'SMS alerts', hint: 'Standard messaging rates may apply.' },
  { value: 'push', label: 'Push notifications' }
];

describe('RadioButtonGroup accessible name', () => {
  it('derives the accessible name from the visible label', () => {
    const view: RenderResult = render(
      <RadioButtonGroup label="Notification preferences" choices={baseChoices} />
    );
    const fieldset = screen.getByRole('group', { name: /notification preferences/i });
    const legend = fieldset.querySelector('legend') as HTMLElement;
    expect(Boolean(legend) && legend.textContent?.trim() === 'Notification preferences').toBe(true);
    view.unmount();
  });

  it('uses ariaLabel when label is omitted', () => {
    const view: RenderResult = render(
      <RadioButtonGroup ariaLabel="Hidden notification options" choices={baseChoices} />
    );
    const fieldset = screen.getByRole('group', { name: /hidden notification options/i });
    const legend = fieldset.querySelector('legend') as HTMLElement;
    expect(legend.className.includes('sr-only')).toBe(true);
    view.unmount();
  });

  it('throws when both label and ariaLabel are empty', () => {
    expect(() =>
      render(<RadioButtonGroup label="   " ariaLabel="  " choices={baseChoices} />)
    ).toThrow('RadioButtonGroup requires a non-empty label or ariaLabel.');
  });

  it('uses the provided id for the fieldset and derived control ids', () => {
    render(<RadioButtonGroup id="rbg-custom" label="With id" choices={baseChoices} />);
    const fieldset = screen.getByRole('group', { name: /with id/i });
    const radios = screen.getAllByRole('radio');
    const idsAreScoped =
      fieldset.getAttribute('id') === 'rbg-custom' &&
      radios.every(radio => radio.getAttribute('id')?.startsWith('rbg-custom-choice-'));
    expect(idsAreScoped).toBe(true);
  });
});

describe('RadioButtonGroup aria-describedby wiring', () => {
  it('references the hint when provided', () => {
    const view: RenderResult = render(
      <RadioButtonGroup label="Newsletter" hint="Select one option" choices={baseChoices} />
    );
    const radiogroup = screen.getByRole('radiogroup');
    const hint = screen.getByText('Select one option');
    expect(radiogroup.getAttribute('aria-describedby') === hint.id).toBe(true);
    view.unmount();
  });

  it('references the error when provided', () => {
    const view: RenderResult = render(
      <RadioButtonGroup label="Newsletter" error="Please make a selection" choices={baseChoices} />
    );
    const radiogroup = screen.getByRole('radiogroup');
    const error = screen.getByText('Please make a selection');
    expect(radiogroup.getAttribute('aria-describedby') === error.id).toBe(true);
    view.unmount();
  });

  it('references both hint and error when present', () => {
    const view: RenderResult = render(
      <RadioButtonGroup
        label="Newsletter"
        hint="Select one option"
        error="Please make a selection"
        choices={baseChoices}
      />
    );
    const radiogroup = screen.getByRole('radiogroup');
    const hint = screen.getByText('Select one option');
    const error = screen.getByText('Please make a selection');
    const expected = `${hint.id} ${error.id}`;
    expect(radiogroup.getAttribute('aria-describedby') === expected).toBe(true);
    view.unmount();
  });
});

describe('RadioButtonGroup choices rendering', () => {
  it('pairs each radio with a label element', () => {
    render(<RadioButtonGroup label="Delivery speed" choices={baseChoices} />);
    const radios = screen.getAllByRole('radio');
    const ok =
      radios.every(radio => {
        const labelId = radio.getAttribute('aria-labelledby');
        if (!labelId) return false;
        const labelEl = document.getElementById(labelId);
        return Boolean(labelEl && labelEl.textContent && labelEl.textContent.trim().length > 0);
      }) && radios.length === baseChoices.length;
    expect(ok).toBe(true);
  });

  it('falls back to choice.value when label is missing', () => {
    render(<RadioButtonGroup label="No labels" choices={[{ value: 'onlyValue' }]} />);
    const radio = screen.getByRole('radio');
    const labelId = radio.getAttribute('aria-labelledby');
    const labelEl = labelId ? document.getElementById(labelId) : null;
    const hasValueFallback = Boolean(labelEl && labelEl.textContent?.trim() === 'onlyValue');
    expect(hasValueFallback).toBe(true);
  });

  it('renders a choice-level hint and wires aria-describedby', () => {
    render(<RadioButtonGroup label="Hints" choices={baseChoices} />);
    const sms = screen.getByRole('radio', { name: /sms alerts/i });
    const hint = screen.getByText('Standard messaging rates may apply.');
    const ok =
      Boolean(hint) &&
      sms.getAttribute('aria-describedby') === hint.id &&
      hint.className.includes('text-color-content-subtle') &&
      hint.className.includes('text-xs');
    expect(ok).toBe(true);
  });

  it('trims choice-level hint text and wires describedBy', () => {
    render(
      <RadioButtonGroup
        label="Hint trim"
        choices={[{ value: 'v1', label: 'One', hint: '   padded hint   ' }]}
      />
    );
    const radio = screen.getByRole('radio', { name: /one/i });
    const hint = screen.getByText('padded hint');
    const trimmedHintValid =
      hint.textContent === 'padded hint' && radio.getAttribute('aria-describedby') === hint.id;
    expect(trimmedHintValid).toBe(true);
  });
});

describe('RadioButtonGroup interactions', () => {
  it('calls onValueChange with the next value when a choice is selected', async () => {
    const user = userEvent.setup();
    const handleChange = jest.fn();
    render(
      <RadioButtonGroup
        label="Delivery speed"
        defaultValue="email"
        onValueChange={handleChange}
        choices={baseChoices}
      />
    );
    const smsRadio = screen.getByRole('radio', { name: /sms alerts/i });
    await user.click(smsRadio);
    expect(handleChange).toHaveBeenCalledWith('sms');
  });

  it('respects per-choice disabled radios', async () => {
    const user = userEvent.setup();
    const handleChange = jest.fn();
    render(
      <RadioButtonGroup
        label="Delivery speed"
        onValueChange={handleChange}
        choices={[
          { value: 'email', label: 'Email updates' },
          { value: 'sms', label: 'SMS alerts', disabled: true },
          { value: 'push', label: 'Push notifications' }
        ]}
      />
    );
    const disabledRadio = screen.getByRole('radio', { name: /sms alerts/i });
    await user.click(disabledRadio);
    const isDisabledAndUnchanged =
      (disabledRadio.hasAttribute('disabled') ||
        disabledRadio.getAttribute('data-disabled') === 'true' ||
        disabledRadio.getAttribute('aria-disabled') === 'true') &&
      handleChange.mock.calls.length === 0;
    expect(isDisabledAndUnchanged).toBe(true);
  });
});

describe('RadioButtonGroup chrome', () => {
  it('omits the info popover when the label is whitespace', () => {
    render(
      <RadioButtonGroup
        label="   "
        ariaLabel="External name"
        info="Should not render trigger"
        choices={baseChoices}
      />
    );
    const hasTrigger = Boolean(screen.queryByRole('button', { name: /info$/i }));
    expect(hasTrigger).toBe(false);
  });

  it('exposes the info popover trigger and content', async () => {
    const user = userEvent.setup();
    render(
      <RadioButtonGroup
        label="Preferences"
        info="More details about notification options."
        choices={baseChoices}
      />
    );
    const trigger = screen.getByRole('button', { name: 'Preferences info' });
    await user.click(trigger);
    await screen.findByText('More details about notification options.');
    await user.keyboard('{Escape}');
    await waitFor(() => {
      const icon = trigger.querySelector('svg');
      const result = {
        label: trigger.getAttribute('aria-label'),
        content: screen.queryByText('More details about notification options.'),
        active: document.activeElement,
        iconHidden: icon?.getAttribute('aria-hidden')
      };
      expect(result).toEqual({
        label: 'Preferences info',
        content: null,
        active: trigger,
        iconHidden: 'true'
      });
    });
  });

  it('renders error chrome and flags invalid state', () => {
    render(
      <RadioButtonGroup label="Error case" error="Selection required" choices={baseChoices} />
    );
    const fieldset = screen.getByRole('group', { name: /error case/i });
    const radiogroup = screen.getByRole('radiogroup');
    const error = screen.getByText('Selection required').parentElement as HTMLElement;
    const icon = error.querySelector('svg');
    const hasErrorState =
      fieldset.getAttribute('data-has-error') === 'true' &&
      radiogroup.getAttribute('aria-invalid') === 'true' &&
      icon?.getAttribute('aria-hidden') === 'true';
    expect(hasErrorState).toBe(true);
  });

  it('applies focus ring token classes on the radio control', () => {
    render(<RadioButtonGroup label="Focus test" choices={baseChoices} />);
    const control = screen.getAllByRole('radio')[0];
    expect(control.className).toContain('focus-visible-brand');
  });
});
